interface IListDelegator{  
     void add(int item);     
     int getItemAtIndex (int index );      
 }

 class Stack extends List implements  IListDelegator {       
         public void add(final int value)    // delegation to the superclass's implementation of this method.  
            {super.addElement(value);}     

         @Override    
		public int getItemAtIndex (int index )      
		 	{return ((List)this).getElemntAtindex((Integer)index ); }    // delegation to the superclass's implementation of this method  
